import { ViewPlugin } from '@codemirror/view';
import type { DecorationSet, EditorView, ViewUpdate } from '@codemirror/view';

import { generateErrorsOrDiagnostics } from '../utils/generate-errors-or-diagnostics.js';

/**
 * View plugin to wrap all filter errors in spans.
 * @internal
 */
export const FilterErrorDecorationPlugin = ViewPlugin.fromClass(
  class {
    decorations: DecorationSet;

    constructor(view: EditorView) {
      this.decorations = generateErrorsOrDiagnostics(view);
    }

    update(update: ViewUpdate) {
      // TODO: This is now called on every transaction, even the ones where
      // it might not be necessary. Improve this with APPDEV-12345.
      this.decorations = generateErrorsOrDiagnostics(update.view);
    }
  },
  {
    decorations: (view) => view.decorations,
  },
);
